def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    num_customers = len(unvisited_customers)

    if num_customers == 0:
        return 'None'

    def distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    cur_distances = [distance(cur_truck_pos, customer) for customer in unvisited_customers]

    if num_customers == 1:
        return 0

    # Evaluate the potential waiting cost at the unvisited customers
    min_distance_indices = np.argsort(cur_distances)
    best_node = min_distance_indices[0]
    cur_best_distance = cur_distances[best_node]

    for idx in min_distance_indices:
        if cur_distances[idx] <= cur_best_distance:
            best_node = idx
