import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    min_distance = float('inf')
    best_node = None
    for idx, customer in enumerate(unvisited_customers):
        distance = np.linalg.norm(cur_truck_pos - customer)
        if distance < min_distance:
            best_node = idx
            min_distance = distance

    # Consider waiting if another truck is already close to the next customer
    for other_truck_pos in all_truck_pos:
        if not np.array_equal(other_truck_pos, cur_truck_pos):
            closest_distance = min(np.linalg.norm(other_truck_pos - customer) for customer in unvisited_customers)
            if closest_distance < min_distance:
                return None

    return best_node
